  ('dietitian-moex-09614', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何者是運動初期階段的主要能量來源？', '["Fat", "Amino acids", "Ketone bodies", "Glycogen"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09615', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種狀況最可能是造成老年人鐵缺乏的主因？', '["不喜歡喝牛奶、皮膚萎縮及在室內活動", "胃酸分泌減少及無法咀嚼肉類", "腸胃道蠕動減緩及內因子分泌減少", "缺乏運動及視力、聽力變差"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09616', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關嬰兒期鐵營養狀況的敘述何者正確？', '["Low-birth-weight嬰兒身體的鐵儲量通常要比足月出生的嬰兒來的高", "在出生前鐵是儲存在胰臟、腎臟和脾臟以供出生後嬰兒使用", "嬰兒所儲存的鐵量甚少，出生體重正常的嬰兒也僅夠1-2星期使用", "出生體重正常的嬰兒，其體內儲存的鐵量可供其出生後的前3個月使用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09617', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '目前認為，在懷孕前及懷孕初期補充何種營養素，可預防neural tube defects？', '["Pyridoxine", "Folate", "Niacin", "Riboflavin"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09618', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關懷孕時生理功能的敘述何者正確？', '["循環系統增大，以適應血量的增加", "腸胃道蠕動加快，而使腹瀉的發生比便秘來的多", "“晨吐是因貧血所造成，應該增加鐵的補充劑量", "懷孕時是一人吃兩人補，所以孕婦要能吃就吃，增加熱量到兩人份"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09619', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '現在對懷孕期鈉攝取量的建議為：', '["限制鈉攝取，且量愈低愈好，以減少發生因懷孕引發之高血壓的危險性", "將烹調使用的鹽全部都改換成含鉀的代鹽，以避免發生懷孕引發之高血壓", "攝取適量的鹽，因為胚胎的發育也需要有適量的鹽", "增加鈉的攝取量50%，以彌補自尿液中的流失量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09620', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '老年人對熱量的需求下降其主因是：', '["老年人的胃口較差", "需要身體運作處理的工作負荷下降", "新陳代謝的速率逐漸下降", "身體須要修補的需求下降"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09621', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關平均需要量（Estimated Average Requirement, EAR）的敘述，何者正確？', '["是健康人群對一營養素的平均需要量", "可滿足97%~98%的健康人", "適用於評估個人的營養素足夠與否", "是沒有足夠的科學證據來計算建議攝取量時的營養素估計值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09622', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '一位身高170 cm，體重58 kg的男性，其BMI值為多少？', '["34", "20", "17", "22"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09623', 'dietitian', 'dietitian-moex-096-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關維生素的敘述，何者錯誤？', '["維生素B 含有鈷（cobalt），若缺乏會引起貧血 12", "缺乏thiamin會引起周邊神經炎（peripheral neuropathy）", "色胺酸（tryptophan）可防止因niacin缺乏所引發的癩皮病（pellagra）", "維生素C是氧化力很強的維生素，如果缺乏會得壞血病（scurvy）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "f3401babe76e", "answer_pdf_sha1": "5c793b5db118", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
